mapper.update:
update wf_process_definition 
set type = #{type}
where id = #{id}

mapper.select:
		select count(o.id) from wf_process_instance o left join wf_process_definition p on p.id = o.process_id


                o.creator in

                    #{operator}



                and p.name in

                    #{name}



                and o.process_id = #{request.processId}



				and p.display_name like #{pattern} 


                and p.type = #{request.processType}


                and o.parent_id = #{request.parentId}


                and o.id not in

                    #{excludedId}



                and o.create_time >= #{request.createTimeStart}


                and o.create_time <= #{request.createTimeEnd}

		select o.id, o.process_id, o.creator, o.create_time, o.parent_id, o.parent_node_name, o.expire_time,
		o.last_update_time, o.last_updator, o.priority, o.variable, o.version 
		from wf_process_instance o left join wf_process_definition p on p.id = o.process_id


                o.creator in

                    #{operator}



                and p.name in

                    #{name}



                and o.process_id = #{request.processId}



				and p.display_name like #{pattern} 


                and p.type = #{request.processType}


                and o.parent_id = #{request.parentId}


                and o.id not in

                    #{excludedId}



                and o.create_time >= #{request.createTimeStart}


                and o.create_time <= #{request.createTimeEnd}



            order by #{request.sortString}

		limit #{rowOffset}, #{request.pageSize}
